 14	import HostnameModal from '@kubevirt-utils/components/HostnameModal/HostnameModal';
 15	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 16	import MoveVMToFolderModal from '@kubevirt-utils/components/MoveVMToFolderModal/MoveVMToFolderModal';
 17	import WorkloadProfileModal from '@kubevirt-utils/components/WorkloadProfileModal/WorkloadProfileModal';
 18	import {
 19	  DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 20	  TREE_VIEW_FOLDERS,
 21	} from '@kubevirt-utils/hooks/useFeatures/constants';
 22	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 23	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 24	import { getAnnotation, getLabel } from '@kubevirt-utils/resources/shared';
 25	import { getVmCPUMemory, WORKLOADS_LABELS } from '@kubevirt-utils/resources/template';
 26	import {
 27	  getCPU,
 28	  getGPUDevices,
 29	  getHostDevices,
 30	  getMachineType,
 31	  getWorkload,
 32	  VM_WORKLOAD_ANNOTATION,
 33	} from '@kubevirt-utils/resources/vm';
 34	import { readableSizeUnit } from '@kubevirt-utils/utils/units';
 35	import { DescriptionList, Grid, GridItem, Switch } from '@patternfly/react-core';
 36	import { VM_FOLDER_LABEL } from '@virtualmachines/tree/utils/constants';
 37	import { printableVMStatus } from '@virtualmachines/utils';
 38	
 39	import { WizardDescriptionItem } from '../../../components/WizardDescriptionItem';
 40	
 41	import VMNameModal from './VMNameModal/VMNameModal';
 42	import { WizardOverviewDisksTable } from './WizardOverviewDisksTable/WizardOverviewDisksTable';
 43	import { WizardOverviewNetworksTable } from './WizardOverviewNetworksTable/WizardOverviewNetworksTable';
