 58	  const { featureEnabled: isDisabledGuestSystemLogs } = useFeatures(
 59	    DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 60	  );
 61	  const description = getAnnotation(vm, 'description');
 62	  const workloadAnnotation = getWorkload(vm);
 63	  const startStrategy = vm?.spec?.template?.spec?.startStrategy;
 64	  const hostname = vm?.spec?.template?.spec?.hostname;
 65	  const vmName = vm?.metadata?.name;
 66	  const networks = vm?.spec?.template?.spec?.networks;
 67	  const interfaces = vm?.spec?.template?.spec?.domain?.devices?.interfaces;
 68	  const disks = vm?.spec?.template?.spec?.domain?.devices?.disks;
 69	  const displayName = tabsData?.overview?.templateMetadata?.displayName;
 70	  const logSerialConsole = (
 71	    vm?.spec?.template?.spec?.domain?.devices as V1Devices & {
 72	      logSerialConsole: boolean;
 73	    }
 74	  )?.logSerialConsole;
 75	
 76	  const hostDevicesCount = getHostDevices(vm)?.length || 0;
 77	  const gpusCount = getGPUDevices(vm)?.length || 0;
 78	  const nDevices = hostDevicesCount + gpusCount;
 79	  const [isChecked, setIsChecked] = useState<boolean>(!!startStrategy);
 80	  const [isCheckedGuestSystemLogAccess, setIsCheckedGuestSystemLogAccess] = useState<boolean>();
