 82	  useEffect(() => {
 83	    setIsCheckedGuestSystemLogAccess(
 84	      (logSerialConsole || logSerialConsole === undefined) && !isDisabledGuestSystemLogs,
 85	    );
 86	  }, [isDisabledGuestSystemLogs, logSerialConsole]);
