 89	    return updateVM((draftVM) => {
 90	      if (!draftVM.spec.template.metadata?.annotations)
 91	        draftVM.spec.template.metadata.annotations = {};
 92	
 93	      draftVM.spec.template.metadata.annotations[VM_WORKLOAD_ANNOTATION] = newWorkload;
 94	    });
 95	  };
 96	
 97	  const updateStartStrategy = (checked: boolean) => {
 98	    return updateVM((vmDraft) => {
 99	      vmDraft.spec.template.spec.startStrategy = checked ? printableVMStatus.Paused : null;
