112	            }
113	            description={vm?.metadata?.name}
114	            helperPopover={{ content: t('Name of the VirtualMachine'), header: t('Name') }}
115	            isEdit
116	            testId="wizard-overview-name"
117	            title={t('Name')}
118	          />
119	
120	          <WizardDescriptionItem
121	            helperPopover={{
122	              content: t('Namespace of the VirtualMachine'),
123	              header: t('Namespace'),
124	            }}
125	            description={vm?.metadata?.namespace}
126	            testId="wizard-overview-namespace"
127	            title={t('Namespace')}
128	          />
