136	                      updateVM((draftVM) => {
137	                        if (!folderName) {
138	                          delete draftVM?.metadata?.labels?.[VM_FOLDER_LABEL];
139	                          return;
140	                        }
141	                        draftVM.metadata.labels = {
142	                          ...draftVM?.metadata?.labels,
143	                          [VM_FOLDER_LABEL]: folderName,
144	                        };
145	                      })
146	                    }
147	                    isOpen={isOpen}
148	                    onClose={onClose}
149	                    vm={vm}
150	                  />
151	                ))
152	              }
153	              description={getLabel(vm, VM_FOLDER_LABEL)}
154	              isEdit
155	              testId="wizard-overview-folder"
156	              title={t('Folder')}
157	            />
158	          )}
159	
160	          <WizardDescriptionItem
161	            helperPopover={{
162	              content: t('Description of the VirtualMachine'),
163	              header: t('Description'),
164	            }}
165	            onEditClick={() =>
166	              createModal(({ isOpen, onClose }) => (
167	                <DescriptionModal
168	                  onSubmit={(updatedDescription) => {
169	                    return updateVM((vmDraft) => {
170	                      if (updatedDescription) {
171	                        vmDraft.metadata.annotations['description'] = updatedDescription;
172	                      } else {
173	                        delete vmDraft.metadata.annotations['description'];
174	                      }
175	                    });
176	                  }}
177	                  isOpen={isOpen}
178	                  obj={vm}
179	                  onClose={onClose}
180	                />
181	              ))
182	            }
183	            description={description}
184	            isEdit
185	            testId="wizard-overview-description"
186	            title={t('Description')}
187	          />
188	
189	          <WizardDescriptionItem
190	            description={displayName}
191	            testId="wizard-overview-operating-system"
192	            title={t('Operating system')}
193	          />
194	
195	          <WizardDescriptionItem
196	            description={t('{{cpuCount}} CPU | {{memory}} Memory', {
197	              cpuCount,
198	              memory: readableSizeUnit(memory),
199	            })}
200	            helperPopover={{
201	              content: (
202	                <CPUDescription
203	                  cpu={getCPU(vm)}
204	                  helperTextResource={CpuMemHelperTextResources.FutureVM}
205	                />
206	              ),
207	              header: t('CPU | Memory'),
208	            }}
209	            onEditClick={() =>
210	              createModal(({ isOpen, onClose }) => (
211	                <CPUMemoryModal isOpen={isOpen} onClose={onClose} onSubmit={updateVM} vm={vm} />
212	              ))
213	            }
214	            className="wizard-overview-description-left-column"
215	            isEdit
216	            testId="wizard-overview-cpu-memory"
217	            title={t('CPU | Memory')}
218	          />
219	
220	          <WizardDescriptionItem
221	            helperPopover={{
222	              content: t('The QEMU machine type.'),
223	              header: t('Machine type'),
224	            }}
225	            className="wizard-overview-description-left-column"
226	            description={getMachineType(vm)}
227	            testId="wizard-overview-machine-type"
228	            title={t('Machine type')}
229	          />
230	
231	          <WizardDescriptionItem
232	            onEditClick={() =>
233	              createModal(({ isOpen, onClose }) => (
234	                <FirmwareBootloaderModal
235	                  isOpen={isOpen}
236	                  onClose={onClose}
237	                  onSubmit={updateVM}
238	                  vm={vm}
239	                />
240	              ))
241	            }
242	            description={getBootloaderTitleFromVM(vm)}
243	            isEdit
244	            testId="wizard-overview-boot-method"
245	            title={t('Boot mode')}
246	          />
247	
248	          <WizardDescriptionItem
249	            description={
250	              <Switch
251	                onChange={(_event, checked) => {
252	                  setIsChecked(checked);
253	                  updateStartStrategy(checked);
254	                }}
255	                id="start-in-pause-mode"
256	                isChecked={isChecked}
257	              />
258	            }
259	            helperPopover={{
260	              content: t(
261	                'Applying the start/pause mode to this Virtual Machine will cause it to partially reboot and pause.',
262	              ),
263	              header: t('Start in pause mode'),
264	            }}
265	            testId="start-in-pause-mode"
266	            title={t('Start in pause mode')}
267	          />
268	
269	          <WizardDescriptionItem
270	            onEditClick={() =>
271	              createModal(({ isOpen, onClose }) => (
272	                <WorkloadProfileModal
273	                  initialWorkload={workloadAnnotation}
274	                  isOpen={isOpen}
275	                  onClose={onClose}
276	                  onSubmit={updateWorkload}
277	                />
278	              ))
279	            }
280	            className="wizard-overview-description-left-column"
281	            description={WORKLOADS_LABELS?.[workloadAnnotation] ?? t('Other')}
282	            isEdit
283	            testId="wizard-overview-workload-profile"
284	            title={t('Workload profile')}
285	          />
286	        </DescriptionList>
287	      </GridItem>
288	      <GridItem rowSpan={4} span={6}>
289	        <DescriptionList className="pf-v6-c-description-list">
290	          <WizardDescriptionItem
291	            description={
292	              <WizardOverviewNetworksTable
293	                interfaces={interfaces}
294	                isInlineGrid
295	                networks={networks}
296	              />
297	            }
298	            onTitleClick={() =>
299	              navigate(`/k8s/ns/${ns}/catalog/template/review/network-interfaces`)
300	            }
301	            count={networks?.length}
302	            testId="wizard-overview-network-interfaces"
303	            title={t('Network interfaces')}
304	          />
305	
306	          <WizardDescriptionItem
307	            count={disks?.length}
308	            description={<WizardOverviewDisksTable isInlineGrid vm={vm} />}
309	            onTitleClick={() => navigate(`/k8s/ns/${ns}/catalog/template/review/disks`)}
310	            testId="wizard-overview-disks"
311	            title={t('Disks')}
312	          />
313	
314	          <WizardDescriptionItem
315	            count={nDevices}
316	            description={<HardwareDevices onSubmit={updateVM} vm={vm} />}
317	            testId="wizard-overview-hardware-devices"
318	            title={t('Hardware devices')}
319	          />
320	
321	          <WizardDescriptionItem
322	            onEditClick={() =>
323	              createModal(({ isOpen, onClose }) => (
324	                <HostnameModal isOpen={isOpen} onClose={onClose} onSubmit={updateVM} vm={vm} />
325	              ))
326	            }
327	            description={hostname || vmName}
328	            isEdit
329	            testId="wizard-overview-hostname"
330	            title={t('Hostname')}
331	          />
332	          <WizardDescriptionItem
333	            description={
334	              <Switch
335	                onChange={(_event, checked) => {
336	                  setIsCheckedGuestSystemLogAccess(checked);
337	                  updateVM((vmDraft) => {
338	                    (
339	                      vmDraft.spec.template.spec.domain.devices as V1Devices & {
340	                        logSerialConsole: boolean;
341	                      }
342	                    ).logSerialConsole = checked ? null : false;
343	                    return vmDraft;
344	                  });
345	                }}
346	                id="guest-system-log-access"
347	                isChecked={isCheckedGuestSystemLogAccess}
348	                isDisabled={isDisabledGuestSystemLogs}
349	              />
350	            }
351	            helperPopover={{
352	              content: isDisabledGuestSystemLogs
353	                ? t('Guest system logs disabled at cluster')
354	                : t(
355	                    'Enables access to the VirtualMachine guest system log. Wait a few seconds for logging to start before viewing the log.',
356	                  ),
357	              header: t('Guest system log access'),
358	            }}
359	            testId="guest-system-log-access"
360	            title={t('Guest system log access')}
361	          />
362	        </DescriptionList>
363	      </GridItem>
364	    </Grid>
365	  );
366	};
367	
368	export default WizardOverviewGrid;

